package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVPrinterTest {

    private CSVPrinter csvPrinter;
    private Appendable mockAppendable;

    @BeforeEach
    void setUp() throws IOException, NoSuchFieldException, IllegalAccessException {
        mockAppendable = mock(Appendable.class);
        CSVFormat format = mock(CSVFormat.class);

        // Use reflection to create CSVPrinter instance by setting private final fields
        csvPrinter = (CSVPrinter) java.lang.reflect.Proxy.newProxyInstance(
                CSVPrinter.class.getClassLoader(),
                new Class[]{CSVPrinter.class},
                (proxy, method, args) -> null);

        // Instead of proxy, better to use constructor directly:
        // But since constructor is not shown fully, assume public constructor exists:

        csvPrinter = new CSVPrinter(mockAppendable, format);
    }

    @Test
    void testGetOut_returnsSameAppendableInstance() throws Exception {
        // Using reflection to access private final field 'out'
        Field outField = CSVPrinter.class.getDeclaredField("out");
        outField.setAccessible(true);
        Appendable outValue = (Appendable) outField.get(csvPrinter);

        Appendable returned = csvPrinter.getOut();

        assertNotNull(returned);
        assertSame(outValue, returned);
    }
}
